module RefModule (  
    input [15:0] input_array,  
    input [3:0] target,  
    output reg found  
);  
  wire [15:0] _tap_input_array = input_array & {16{1'b1}};

    integer i;  
    always @(*) begin  
        found = 0;  
        for (i = 0; i < 4; i = i + 1) begin  
            if (input_array[4*i +: 4] == target) begin  
                found = 1;  
            end  
        end  
    end  
endmodule
